// ── Solar Subsidy Calculator ──
function calcSolarSubsidy(kw, state) {
  const isUP = state === "UP";
  // Central PM Surya Ghar
  let central = kw <= 1 ? 30000 : kw <= 2 ? 60000 : 78000;
  // UP State extra
  let stateSubsidy = 0;
  if (isUP) {
    stateSubsidy = kw <= 1 ? 15000 : kw <= 2 ? 30000 : 30000;
  }
  const total = central + stateSubsidy;
  // Approx system cost
  const costPerKw = kw <= 2 ? 67000 : kw <= 5 ? 60000 : 55000;
  const systemCost = Math.round(kw * costPerKw);
  const netCost = Math.max(0, systemCost - total);
  const annualSaving = Math.round(kw * 1400 * 7); // ~1400 units/kw/year @ ₹7/unit
  const payback = netCost > 0 ? (netCost / annualSaving).toFixed(1) : "0";
  return { central, stateSubsidy, total, systemCost, netCost, annualSaving, payback };
}

// ── Language Detection ──
function detectLang(text) {
  if (/[\u0900-\u097F]/.test(text)) return "hindi";
  if (/\b(kya|hai|mujhe|mera|meri|aap|nahi|haan|karo|bolo|kitna|kaise|kyun|chahiye|batao|accha|theek|bilkul|abhi|phir|toh|aur|ya|se|ke|ka|ki|ko|me|pe|tha|thi|the|ho|hoga|lena|dena|woh|yeh|sab|kuch|bahut|thoda|zyada|pehle|baad|solar|bijli|ghar|chhat|subsidy)\b/i.test(text)) return "hinglish";
  return "english";
}

function langInstruction(lang) {
  if (lang === "hindi") return "CRITICAL: Reply ENTIRELY in proper Hindi using Devanagari script. Only technical terms like KW, solar, subsidy, EMI may stay in English.";
  if (lang === "hinglish") return "CRITICAL: Reply in natural Hinglish — Hindi (Devanagari) for conversational words, English for technical terms.";
  return "CRITICAL: Reply entirely in clear, professional English.";
}

