function renderText(text){
  return text.split("\n").map((line,i)=>{
    const parts=line.split(/\*\*(.*?)\*\*/g);
    return <p key={i} style={{margin:"3px 0",lineHeight:1.75}}>{parts.map((p,j)=>j%2===1?<strong key={j}>{p}</strong>:p)}</p>;
  });
}

