function LeadCard({agent,onSubmit,onSkip,lang}){
  const [name,setName]=useState(""); const [phone,setPhone]=useState("");
  const ready=phone.length===10;
  const isH=lang!=="english";
  const submit=()=>{
    if(!ready)return;
    const txt=isH
      ?`नमस्ते! मैं ${name||"एक उपयोगकर्ता"} हूँ।%0A${agent.hindi} के बारे में जानकारी चाहिए।%0AMobile: ${phone}%0ASAHAYAK App से आ रहा/रही हूँ।`
      :`Hello! I am ${name||"a user"}.%0ANeed help with ${agent.label}.%0AMobile: ${phone}%0AFrom SAHAYAK App.`;
    window.open(`${WHATSAPP_LINK}?text=${txt}`,"_blank");
    onSubmit(name);
  };
  return(
    <div style={{margin:"4px 0 8px",borderRadius:18,background:`${agent.color}10`,border:`1px solid ${agent.color}40`,padding:16,boxShadow:`0 4px 24px ${agent.glow}`}}>
      <div style={{fontWeight:800,fontSize:14,marginBottom:4,color:agent.color}}>🎯 {isH?"निःशुल्क कॉलबैक पाएं!":"Get a Free Expert Callback!"}</div>
      <div style={{fontSize:12,opacity:0.5,marginBottom:12}}>{isH?"हमारे विशेषज्ञ WhatsApp पर संपर्क करेंगे":"Our expert will reach you on WhatsApp"}</div>
      <input placeholder={isH?"आपका नाम (वैकल्पिक)":"Your name (optional)"} value={name} onChange={e=>setName(e.target.value)} style={{width:"100%",marginBottom:8,padding:"9px 13px",borderRadius:11,border:`1px solid ${agent.color}40`,background:"rgba(255,255,255,0.06)",color:"#fff",fontSize:13,outline:"none",fontFamily:"inherit",boxSizing:"border-box"}}/>
      <input placeholder={isH?"मोबाइल नंबर (10 अंक)":"Mobile number (10 digits)"} value={phone} onChange={e=>setPhone(e.target.value.replace(/\D/,"").slice(0,10))} type="tel" style={{width:"100%",marginBottom:12,padding:"9px 13px",borderRadius:11,border:`1px solid ${agent.color}40`,background:"rgba(255,255,255,0.06)",color:"#fff",fontSize:13,outline:"none",fontFamily:"inherit",boxSizing:"border-box"}}/>
      <div style={{display:"flex",gap:8}}>
        <button onClick={submit} style={{flex:1,padding:"11px 0",borderRadius:11,border:"none",background:ready?agent.grad:"rgba(255,255,255,0.08)",color:"#fff",fontWeight:800,cursor:ready?"pointer":"not-allowed",fontSize:13,fontFamily:"inherit"}}>
          📱 {isH?"WhatsApp पर भेजें":"Send on WhatsApp"}
        </button>
        <button onClick={onSkip} style={{padding:"11px 14px",borderRadius:11,border:"1px solid rgba(255,255,255,0.15)",background:"transparent",color:"rgba(255,255,255,0.45)",cursor:"pointer",fontSize:12,fontFamily:"inherit"}}>{isH?"बाद में":"Later"}</button>
      </div>
    </div>
  );
}

export default function SahayakV5(){
  const [screen,setScreen]=useState("home");
  const [agent,setAgent]=useState(null);
  const [messages,setMessages]=useState([]);
  const [input,setInput]=useState("");
  const [loading,setLoading]=useState(false);
  const [showLead,setShowLead]=useState(false);
  const [showCalc,setShowCalc]=useState(false);
  const [uiLang,setUiLang]=useState("hindi");
  const chatEndRef=useRef(null);

  useEffect(()=>{chatEndRef.current?.scrollIntoView({behavior:"smooth"});},[messages,showLead,showCalc]);
  useEffect(()=>{
    const u=messages.filter(m=>m.role==="user").length;
    if(u>=3&&!showLead)setShowLead(true);
    if(agent?.isSolar&&u===1&&!showCalc)setShowCalc(true);
  },[messages]);

  const openAgent=(ag)=>{
    setAgent(ag);
    const isH=uiLang!=="english";
    setMessages([{role:"assistant",content:ag.isSolar
      ?(isH
        ?`नमस्ते! मैं SAHAYAK का **सोलर रूफटॉप विशेषज्ञ** हूँ! ☀️🙏\n\nमैं **PM सूर्य घर अधिकृत वेंडर** और **MFINS Solar Channel Partner** हूँ — पूरे भारत में सेवा उपलब्ध।\n\nनीचे **सब्सिडी कैलकुलेटर** में अपनी जानकारी भरें या कोई भी सवाल पूछें! 👇`
        :`Hello! I'm SAHAYAK's **Solar Rooftop Expert**! ☀️🙏\n\nI'm a **PM Surya Ghar Authorized Vendor** and **MFINS Solar Channel Partner** — serving Pan-India.\n\nUse the **Subsidy Calculator** below or ask me anything! 👇`)
      :(isH
        ?`नमस्ते! मैं SAHAYAK का **${ag.hindi} विशेषज्ञ** हूँ! 🙏\n\nकोई भी सवाल पूछें — **बिल्कुल मुफ्त**। नीचे से चुनें या लिखें! 👇`
        :`Hello! I'm your **${ag.label} Expert** from SAHAYAK! 🙏\n\nAsk me anything — completely **free**. Pick a question or type below! 👇`)}]);
    setShowLead(false); setShowCalc(false); setScreen("chat");
  };

  const handleCalcResult=(kw,state,type,calc)=>{
    const isH=uiLang!=="english";
    const isComm=type==="commercial";
    const txt=isH
      ?`नमस्ते! मैं ${kw}KW ${isComm?"व्यावसायिक":"घरेलू"} सोलर में रुचि रखता/रखती हूँ।%0AराEstate: ${state}%0A${!isComm?`अनुमानित सब्सिडी: ₹${calc.total.toLocaleString("en-IN")}%0A`:""}SAHAYAK App से आ रहा/रही हूँ।`
      :`Hello! I'm interested in ${kw}KW ${isComm?"commercial":"residential"} solar.%0AState: ${state}%0A${!isComm?`Est. Subsidy: ₹${calc.total.toLocaleString("en-IN")}%0A`:""}From SAHAYAK App.`;
    window.open(`${WHATSAPP_LINK}?text=${txt}`,"_blank");
    setShowCalc(false);
    setMessages(prev=>[...prev,{role:"assistant",content:isH
      ?`बहुत अच्छा! 🎉 आपकी जानकारी WhatsApp पर भेज दी गई है।\n\n**हमारे विशेषज्ञ जल्द ही मुफ्त साइट सर्वे के लिए संपर्क करेंगे।** तब तक और सवाल पूछ सकते हैं! ☀️`
      :`Excellent! 🎉 Your details have been sent on WhatsApp.\n\n**Our expert will contact you soon for a free site survey.** Feel free to ask more questions! ☀️`}]);
  };

  const send=async(text)=>{
    const q=text||input.trim();
    if(!q||loading)return;
    setInput("");
    const lang=detectLang(q);
    const updated=[...messages,{role:"user",content:q}];
    setMessages(updated); setLoading(true);
    try{
      const sysPrompt=agent.isSolar?`${SOLAR_PROMPT}\n\n${langInstruction(lang)}`:`${BASE_PROMPT(agent.domain)}\n\n${langInstruction(lang)}`;
      const res=await fetch("/api/chat",{
        method:"POST",headers:{"Content-Type":"application/json"},
        body:JSON.stringify({system:sysPrompt,messages:updated.map(m=>({role:m.role,content:m.content}))})
      });
      const data=await res.json();
      const reply=data.content?.map(c=>c.text||"").join("")||"कृपया पुनः प्रयास करें।";
      setMessages([...updated,{role:"assistant",content:reply}]);
    }catch{
      setMessages([...updated,{role:"assistant",content:"नेटवर्क त्रुटि। कृपया पुनः प्रयास करें।"}]);
    }
    setLoading(false);
  };

  const handleLeadSubmit=(name)=>{
    setShowLead(false);
    const isH=uiLang!=="english";
    setMessages(prev=>[...prev,{role:"assistant",content:isH
      ?`धन्यवाद${name?`, ${name} जी`:""}! 🙏 हमारे विशेषज्ञ जल्द ही WhatsApp पर संपर्क करेंगे। तब तक और सवाल पूछ सकते हैं! 😊`
      :`Thank you${name?`, ${name}`:""}! 🙏 Our expert will contact you on WhatsApp shortly. Feel free to ask more! 😊`}]);
  };

  const isH=uiLang!=="english";

  // ── HOME ──
  if(screen==="home") return(
    <div style={{minHeight:"100vh",fontFamily:"'Noto Sans Devanagari','Segoe UI',sans-serif",background:"#09090f",color:"#fff",display:"flex",flexDirection:"column",backgroundImage:"radial-gradient(ellipse 80% 45% at 50% -5%,rgba(255,153,0,0.13) 0%,transparent 70%),radial-gradient(ellipse 55% 35% at 85% 105%,rgba(19,136,8,0.1) 0%,transparent 70%)"}}>
      <div style={{padding:"13px 18px",display:"flex",alignItems:"center",justifyContent:"space-between",borderBottom:"1px solid rgba(255,255,255,0.06)"}}>
        <div style={{display:"flex",alignItems:"center",gap:10}}>
          <img src={LOGO_B64} alt="SAHAYAK" style={{width:46,height:46,borderRadius:12,objectFit:"cover",boxShadow:"0 2px 16px rgba(255,153,0,0.3)"}}/>
          <div>
            <div style={{fontWeight:900,fontSize:19,letterSpacing:2,background:"linear-gradient(90deg,#ff9900,#fff 50%,#138808)",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent"}}>SAHAYAK</div>
            <div style={{fontSize:9.5,opacity:0.38,letterSpacing:0.4}}>GST Suvidha • VLE-IRDAI • MFINS Solar</div>
          </div>
        </div>
        <div style={{display:"flex",background:"rgba(255,255,255,0.05)",borderRadius:10,padding:3}}>
          {["hindi","english"].map(l=>(
            <button key={l} onClick={()=>setUiLang(l)} style={{padding:"5px 11px",borderRadius:8,border:"none",background:uiLang===l?"rgba(255,153,0,0.85)":"transparent",color:"#fff",fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"inherit",transition:"all 0.2s"}}>
              {l==="hindi"?"हिंदी":"EN"}
            </button>
          ))}
        </div>
      </div>

      <div style={{textAlign:"center",padding:"22px 20px 12px"}}>
        <div style={{fontSize:11.5,color:"#ff9900",fontWeight:700,letterSpacing:1.5,marginBottom:8,opacity:0.9}}>
          {isH?"🇮🇳 बीमा • टैक्स • सोलर — एक ही जगह":"🇮🇳 INSURANCE • TAX • SOLAR — ONE PLATFORM"}
        </div>
        <h2 style={{margin:0,fontSize:20,fontWeight:900,lineHeight:1.45,color:"#fff"}}>
          {isH?<>हर वित्तीय समस्या का<br/><span style={{color:"#ff9900"}}>सरल समाधान</span></>:<>Simple answers to every<br/><span style={{color:"#ff9900"}}>financial question</span></>}
        </h2>
        <p style={{fontSize:11.5,opacity:0.4,marginTop:7}}>{isH?"बिल्कुल मुफ्त • हिंदी और English • पूरे भारत में":"100% Free • Hindi & English • Pan-India Service"}</p>
      </div>

      {/* Solar highlight banner */}
      <div onClick={()=>openAgent(AGENTS.find(a=>a.id==="solar"))} style={{margin:"0 14px 14px",padding:"13px 16px",borderRadius:16,background:"linear-gradient(135deg,rgba(243,156,18,0.15),rgba(211,84,0,0.1))",border:"1px solid rgba(243,156,18,0.4)",cursor:"pointer",display:"flex",alignItems:"center",gap:12,transition:"all 0.2s"}}
        onMouseEnter={e=>e.currentTarget.style.background="linear-gradient(135deg,rgba(243,156,18,0.25),rgba(211,84,0,0.18))"}
        onMouseLeave={e=>e.currentTarget.style.background="linear-gradient(135deg,rgba(243,156,18,0.15),rgba(211,84,0,0.1))"}>
        <div style={{fontSize:32}}>☀️</div>
        <div style={{flex:1}}>
          <div style={{fontWeight:800,fontSize:13,color:"#f39c12"}}>{isH?"PM सूर्य घर — अभी चेक करें!":"PM Surya Ghar — Check Now!"}</div>
          <div style={{fontSize:11,opacity:0.55,marginTop:2}}>{isH?"UP में ₹1,08,000 तक सब्सिडी • मुफ्त साइट सर्वे":"UP subsidy upto ₹1,08,000 • Free Site Survey"}</div>
        </div>
        <div style={{fontSize:18,color:"#f39c12",opacity:0.6}}>→</div>
      </div>

      <div style={{flex:1,padding:"0 14px 20px",maxWidth:560,margin:"0 auto",width:"100%",boxSizing:"border-box"}}>
        <p style={{fontSize:11.5,opacity:0.32,textAlign:"center",marginBottom:12}}>{isH?"अन्य विशेषज्ञ 👇":"Other Experts 👇"}</p>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:9}}>
          {AGENTS.filter(a=>a.id!=="solar").map((ag,idx)=>(
            <button key={ag.id} onClick={()=>openAgent(ag)} style={{background:"rgba(255,255,255,0.03)",border:`1px solid ${ag.color}22`,borderRadius:16,padding:"14px 10px",cursor:"pointer",textAlign:"center",color:"#fff",fontFamily:"inherit",transition:"all 0.22s",animation:`fadeUp 0.4s ${idx*0.06}s both`}}
              onMouseEnter={e=>{e.currentTarget.style.background=`${ag.color}14`;e.currentTarget.style.borderColor=`${ag.color}55`;e.currentTarget.style.transform="translateY(-2px)";}}
              onMouseLeave={e=>{e.currentTarget.style.background="rgba(255,255,255,0.03)";e.currentTarget.style.borderColor=`${ag.color}22`;e.currentTarget.style.transform="";}}>
              <div style={{fontSize:22,marginBottom:7}}>{ag.icon}</div>
              <div style={{fontWeight:800,fontSize:10.5,color:ag.color,lineHeight:1.3}}>{ag.hindi}</div>
            </button>
          ))}
        </div>

        <a href={WHATSAPP_LINK} target="_blank" rel="noreferrer" style={{display:"flex",alignItems:"center",justifyContent:"center",gap:10,marginTop:12,padding:"11px 16px",borderRadius:13,background:"rgba(37,211,102,0.07)",border:"1px solid rgba(37,211,102,0.22)",textDecoration:"none",color:"#fff",transition:"all 0.2s"}}
          onMouseEnter={e=>e.currentTarget.style.background="rgba(37,211,102,0.14)"}
          onMouseLeave={e=>e.currentTarget.style.background="rgba(37,211,102,0.07)"}>
          <span style={{fontSize:18}}>💬</span>
          <div style={{textAlign:"left"}}>
            <div style={{fontSize:12.5,fontWeight:800,color:"#25d366"}}>{isH?"सीधे WhatsApp पर बात करें":"Chat directly on WhatsApp"}</div>
            <div style={{fontSize:10,opacity:0.45}}>wa.me/xsuvidha • {isH?"निःशुल्क":"Free"}</div>
          </div>
          <span style={{marginLeft:"auto",fontSize:15,opacity:0.4}}>→</span>
        </a>
      </div>
      <style>{`@keyframes fadeUp{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:none}} ::-webkit-scrollbar{width:3px} ::-webkit-scrollbar-thumb{background:rgba(255,255,255,0.12);border-radius:3px} @keyframes bounce{0%,60%,100%{transform:translateY(0)}30%{transform:translateY(-6px)}} input::placeholder,textarea::placeholder{color:rgba(255,255,255,0.25)}`}</style>
    </div>
  );

  // ── CHAT ──
  const starters=isH?agent.starters.hindi:agent.starters.english;
  return(
    <div style={{minHeight:"100vh",fontFamily:"'Noto Sans Devanagari','Segoe UI',sans-serif",background:"#09090f",color:"#fff",display:"flex",flexDirection:"column",backgroundImage:`radial-gradient(ellipse 70% 40% at 50% 0%,${agent.glow} 0%,transparent 70%)`}}>
      <div style={{padding:"10px 14px",display:"flex",alignItems:"center",gap:10,background:"rgba(0,0,0,0.55)",backdropFilter:"blur(14px)",borderBottom:`1px solid ${agent.color}22`,position:"sticky",top:0,zIndex:10}}>
        <button onClick={()=>setScreen("home")} style={{background:"none",border:"none",color:"#fff",fontSize:22,cursor:"pointer",opacity:0.6,padding:0,lineHeight:1}}>←</button>
        <img src={LOGO_B64} alt="logo" style={{width:38,height:38,borderRadius:10,objectFit:"cover",boxShadow:`0 0 14px ${agent.glow}`}}/>
        <div style={{flex:1}}>
          <div style={{fontWeight:800,fontSize:13.5}}>{agent.hindi} {isH?"विशेषज्ञ":"Expert"}</div>
          <div style={{fontSize:10,color:"#2ecc71",display:"flex",alignItems:"center",gap:4}}>
            <span style={{width:6,height:6,borderRadius:"50%",background:"#2ecc71",display:"inline-block"}}/>
            {isH?"ऑनलाइन • निःशुल्क • पूरे भारत में":"Online • Free • Pan-India"}
          </div>
        </div>
        <a href={`${WHATSAPP_LINK}?text=${isH?`नमस्ते! मुझे ${agent.hindi} के बारे में बात करनी है।`:`Hello! I need help with ${agent.label}.`}`} target="_blank" rel="noreferrer"
          style={{background:"#25d366",borderRadius:10,padding:"7px 12px",fontSize:11,color:"#fff",textDecoration:"none",fontWeight:800,whiteSpace:"nowrap"}}>📱 WhatsApp</a>
      </div>

      {messages.length<=1&&(
        <div style={{padding:"10px 14px 4px",display:"flex",flexWrap:"wrap",gap:8}}>
          {starters.map((q,i)=>(
            <button key={i} onClick={()=>send(q)} style={{background:`${agent.color}16`,border:`1px solid ${agent.color}42`,borderRadius:22,padding:"7px 14px",color:"#fff",cursor:"pointer",fontSize:12.5,fontFamily:"inherit",transition:"all 0.18s",lineHeight:1.4}}
              onMouseEnter={e=>e.currentTarget.style.background=`${agent.color}30`}
              onMouseLeave={e=>e.currentTarget.style.background=`${agent.color}16`}>{q}</button>
          ))}
        </div>
      )}

      <div style={{flex:1,overflowY:"auto",padding:"10px 14px",display:"flex",flexDirection:"column",gap:10}}>
        {messages.map((msg,i)=>(
          <div key={i} style={{display:"flex",justifyContent:msg.role==="user"?"flex-end":"flex-start",alignItems:"flex-end",gap:8}}>
            {msg.role==="assistant"&&<img src={LOGO_B64} alt="s" style={{width:30,height:30,borderRadius:"50%",objectFit:"cover",flexShrink:0,boxShadow:`0 0 10px ${agent.glow}`}}/>}
            <div style={{maxWidth:"78%",background:msg.role==="user"?agent.grad:"rgba(255,255,255,0.06)",borderRadius:msg.role==="user"?"20px 20px 5px 20px":"20px 20px 20px 5px",padding:"11px 15px",fontSize:14,border:msg.role==="assistant"?`1px solid ${agent.color}22`:"none",boxShadow:msg.role==="user"?`0 4px 16px ${agent.glow}`:"none"}}>
              {renderText(msg.content)}
            </div>
          </div>
        ))}

        {showCalc&&agent.isSolar&&<SolarCalc onResult={handleCalcResult} lang={uiLang}/>}
        {showLead&&<LeadCard agent={agent} onSubmit={handleLeadSubmit} onSkip={()=>setShowLead(false)} lang={uiLang}/>}

        {loading&&(
          <div style={{display:"flex",alignItems:"flex-end",gap:8}}>
            <img src={LOGO_B64} alt="s" style={{width:30,height:30,borderRadius:"50%",objectFit:"cover",flexShrink:0}}/>
            <div style={{background:"rgba(255,255,255,0.06)",borderRadius:"20px 20px 20px 5px",padding:"12px 16px",display:"flex",gap:5,border:`1px solid ${agent.color}22`}}>
              {[0,1,2].map(i=><div key={i} style={{width:7,height:7,borderRadius:"50%",background:agent.color,animation:`bounce 1.2s ${i*0.2}s infinite`}}/>)}
            </div>
          </div>
        )}
        <div ref={chatEndRef}/>
      </div>

      <div style={{padding:"10px 14px 14px",background:"rgba(0,0,0,0.55)",backdropFilter:"blur(14px)",borderTop:`1px solid ${agent.color}18`}}>
        <div style={{display:"flex",gap:8,alignItems:"flex-end"}}>
          <textarea value={input} onChange={e=>setInput(e.target.value)}
            onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();send();}}}
            placeholder={isH?"अपना सवाल लिखें... (हिंदी या English)":"Ask your question... (Hindi or English)"}
            rows={1} style={{flex:1,background:"rgba(255,255,255,0.05)",border:`1px solid ${agent.color}30`,borderRadius:14,padding:"11px 14px",color:"#fff",fontSize:14,resize:"none",outline:"none",fontFamily:"inherit",minHeight:44,maxHeight:110,lineHeight:1.5,transition:"border-color 0.2s"}}
            onFocus={e=>e.target.style.borderColor=agent.color}
            onBlur={e=>e.target.style.borderColor=`${agent.color}30`}/>
          <button onClick={()=>send()} disabled={!input.trim()||loading} style={{width:44,height:44,borderRadius:13,flexShrink:0,background:input.trim()&&!loading?agent.grad:"rgba(255,255,255,0.06)",border:"none",cursor:input.trim()&&!loading?"pointer":"not-allowed",color:"#fff",fontSize:19,display:"flex",alignItems:"center",justifyContent:"center",transition:"all 0.2s",boxShadow:input.trim()&&!loading?`0 4px 14px ${agent.glow}`:"none"}}>→</button>
        </div>
        <div style={{fontSize:10,opacity:0.2,textAlign:"center",marginTop:7,letterSpacing:0.5}}>SAHAYAK • GST Suvidha • VLE-IRDAI • MFINS Solar • 🇮🇳</div>
      </div>
      <style>{`@keyframes bounce{0%,60%,100%{transform:translateY(0)}30%{transform:translateY(-6px)}} textarea::placeholder,input::placeholder{color:rgba(255,255,255,0.25)} ::-webkit-scrollbar{width:3px} ::-webkit-scrollbar-thumb{background:rgba(255,255,255,0.1);border-radius:3px}`}</style>
    </div>
  );
}
